@plant.pollinated = true

// Bee carries pollen from @donor's flower to @recipient. The recipient's
// destined seed gets inscribed with this action, so when it's planted next
// season we know its other parent.

queue action germinate:
                with:
                    @plant: @plant
                    @plot: @plot
                urgent: true

queue action set-fruit:
                with:
                    @plant: @plant
                    @plot: @plot
                urgent: true

queue action ripen:
                with:
                    @plant: @plant
                    @plot: @plot
                urgent: true

queue action go-to-seed:
                with:
                    @plant: @plant
                    @plot: @plot
                    @seed: @seed
                urgent: true


// ── Queries (search filters used by the sifting patterns below) ─────────────

queue action leaf-out:
                with:
                    @plant: @plant
                    @plot: @plot
                urgent: true

queue action flower:
                with:
                    @plant: @plant
                    @plot: @plot
                urgent: true
